function Read-DerLength{param([byte[]]$d,[ref]$o)if($d[$o.Value]-lt0x80){$l=$d[$o.Value];$o.Value++;return$l}$n=$d[$o.Value]-band0x7F;$o.Value++;$len=0;for($i=0;$i-lt$n;$i++){$len=($len-shl8)-bor$d[$o.Value];$o.Value++};return$len}
function Read-DerInteger{param([byte[]]$d,[ref]$o)if($d[$o.Value]-ne0x02){throw"bad"}$o.Value++;$l=Read-DerLength $d $o;$v=[byte[]]::new($l);[Array]::Copy($d,$o.Value,$v,0,$l);$s=if($v.Length-gt1-and$v[0]-eq0){1}else{0};$t=[byte[]]::new($v.Length-$s);[Array]::Copy($v,$s,$t,0,$t.Length);$o.Value+=$l;return$t}
$pem=[System.IO.File]::ReadAllText("bybit_private.pem");$b64=($pem -replace '-----.+-----','' -replace '\s','');$der=[System.Convert]::FromBase64String($b64);$off=0;if($der[$off]-ne0x30){throw"bad"};$off++;Read-DerLength $der([ref]$off)|Out-Null;$p=New-Object System.Security.Cryptography.RSAParameters;Read-DerInteger $der([ref]$off)|Out-Null;$p.Modulus=Read-DerInteger $der([ref]$off);$p.Exponent=Read-DerInteger $der([ref]$off);$p.D=Read-DerInteger $der([ref]$off);$p.P=Read-DerInteger $der([ref]$off);$p.Q=Read-DerInteger $der([ref]$off);$p.DP=Read-DerInteger $der([ref]$off);$p.DQ=Read-DerInteger $der([ref]$off);$p.InverseQ=Read-DerInteger $der([ref]$off);$rsa=New-Object System.Security.Cryptography.RSACryptoServiceProvider;$rsa.ImportParameters($p)
$ak="gkPx5g3xgL2pthIg16";$rw="5000"
function Call-API($ep,$q){$ts=[DateTimeOffset]::UtcNow.ToUnixTimeMilliseconds();$b=[Text.Encoding]::UTF8.GetBytes("${ts}${ak}${rw}${q}");$h=[Security.Cryptography.SHA256]::Create();$sg=[Convert]::ToBase64String($rsa.SignData($b,$h));$hd=@{"X-BAPI-API-KEY"=$ak;"X-BAPI-TIMESTAMP"="$ts";"X-BAPI-SIGN"=$sg;"X-BAPI-RECV-WINDOW"=$rw;"X-BAPI-SIGN-TYPE"="2";"User-Agent"="bybit-skill/1.4.2"};try{return(Invoke-WebRequest -Uri "https://api.bybit.com$ep`?$q" -Headers $hd -UseBasicParsing -TimeoutSec 20|ConvertFrom-Json)}catch{return$null}}
$r=Call-API -ep "/v5/market/kline" -q "category=spot&symbol=SOLUSDT&interval=360&limit=999"
if ($r -and $r.result -and $r.result.list) { Write-Output "OK: $($r.result.list.Count) candles" } else { Write-Output "FAILED: no data"; if ($r) { Write-Output ($r | ConvertTo-Json -Depth 3) } }
